import xml.etree.ElementTree as ET

f = '/work/output/artifacts/skill-bpmn-e2e-invoice-exception-triage/InvoiceExceptionTriage/InvoiceExceptionTriage.bpmn'
tree = ET.parse(f)
root = tree.getroot()

BN = 'http://www.omg.org/spec/BPMN/20100524/MODEL'
DI = 'http://www.omg.org/spec/BPMN/20100524/DI'
UP = 'http://uipath.org/schema/bpmn'

def b(t): return f'{{{BN}}}{t}'
def u(t): return f'{{{UP}}}{t}'

proc = root.find(b('process'))
errors = []

# Collect all element IDs in the process
ids = {}
for el in proc.iter():
    eid = el.get('id')
    if eid:
        tag = el.tag.split('}')[1] if '}' in el.tag else el.tag
        ids[eid] = tag

print("IDs:", list(ids.keys()))

# Sequence flows
flows = {}
for sf in proc.findall(b('sequenceFlow')):
    fid = sf.get('id')
    src = sf.get('sourceRef')
    tgt = sf.get('targetRef')
    flows[fid] = (src, tgt)
    if src not in ids: errors.append(f"FLOW {fid}: sourceRef {src} not found")
    if tgt not in ids: errors.append(f"FLOW {fid}: targetRef {tgt} not found")

print("Flows:", flows)

# Check XOR gateway default and conditions
for gw in proc.findall(b('exclusiveGateway')):
    gid = gw.get('id')
    default = gw.get('default')
    outgoing = [o.text for o in gw.findall(b('outgoing'))]
    if default not in outgoing: errors.append(f"GW {gid}: default {default} not in outgoing {outgoing}")
    for fid in outgoing:
        if fid == default: continue
        sf = proc.find(f'.//{b("sequenceFlow")}[@id="{fid}"]')
        cond = sf.find(b('conditionExpression')) if sf is not None else None
        if cond is None: errors.append(f"GW {gid}: non-default outgoing {fid} missing conditionExpression")
        elif not cond.text.startswith('='): errors.append(f"GW {gid}: condition {fid} must start with =")

# Check BPMNDiagram shapes and edges
diag = root.find('{http://www.omg.org/spec/BPMN/20100524/DI}BPMNDiagram')
plane = diag.find('{http://www.omg.org/spec/BPMN/20100524/DI}BPMNPlane')
shaped = set()
edged = set()
for sh in plane.findall('{http://www.omg.org/spec/BPMN/20100524/DI}BPMNShape'):
    ref = sh.get('bpmnElement')
    if ref: shaped.add(ref)
for ed in plane.findall('{http://www.omg.org/spec/BPMN/20100524/DI}BPMNEdge'):
    ref = ed.get('bpmnElement')
    if ref: edged.add(ref)

# Check every visible node has a shape
node_tags = {'startEvent','endEvent','scriptTask','userTask','exclusiveGateway','task','serviceTask','userTask','sendTask'}
for el in proc:
    tag = el.tag.split('}')[1] if '}' in el.tag else el.tag
    eid = el.get('id')
    if tag in node_tags and eid and eid not in shaped:
        errors.append(f"SHAPE MISSING: {eid} ({tag})")

# Check every flow has an edge
for fid in flows:
    if fid not in edged:
        errors.append(f"EDGE MISSING: {fid}")

# Check vars refs in conditions
vars_ids = set()
ext = proc.find(b('extensionElements'))
if ext is not None:
    vs = ext.find(u('variables'))
    if vs is not None:
        for v in vs:
            vars_ids.add(v.get('id'))

print("Variable IDs:", vars_ids)

# Check condition references
for sf in proc.findall(b('sequenceFlow')):
    cond = sf.find(b('conditionExpression'))
    if cond is not None and cond.text:
        # extract vars.XXX references
        import re
        refs = re.findall(r'vars\.(\w+)', cond.text)
        for ref in refs:
            if ref not in vars_ids:
                errors.append(f"COND var ref vars.{ref} not declared in flow {sf.get('id')}")

if errors:
    print("\nERRORS:")
    for e in errors: print(" ", e)
else:
    print("\nAll structural checks PASSED")
